#include "controller.h"

/* State machine transitions */
static void state_transition(controller_t *controller, controller_input_t input)
{
    if (controller == 0) {
        return;
    }

    /* SAFE_VENT -> PRESSURIZING: compressor_on = true, vent_open = false, state = PRESSURIZING */
    if (controller->state == CONTROLLER_STATE_SAFE_VENT && input.kind == CONTROLLER_INPUT_PRESSURE) {
        controller->compressor_on = true;
        controller->vent_open = false;
        controller->state = CONTROLLER_STATE_PRESSURIZING;
        return;
    }

    /* SAFE_VENT -> HOLDING: compressor_on = false, vent_open = true, state = HOLDING */
    if (controller->state == CONTROLLER_STATE_SAFE_VENT && input.kind == CONTROLLER_INPUT_DOOR_CLOSED) {
        controller->compressor_on = false;
        controller->vent_open = true;
        controller->state = CONTROLLER_STATE_HOLDING;
        return;
    }

    /* SAFE_VENT -> RELIEVING: compressor_on = false, vent_open = true, state = RELIEVING */
    if (controller->state == CONTROLLER_STATE_SAFE_VENT && input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT) {
        controller->compressor_on = false;
        controller->vent_open = true;
        controller->state = CONTROLLER_STATE_RELIEVING;
        return;
